(function(){
  var modal=null;
  function ensure(){
    if(modal) return modal;
    var d=document.createElement('div');
    d.innerHTML='<div class="fmodal" hidden><div class="fmodal-panel"><button class="fmodal-x" aria-label="Cerrar">&times;</button><div class="fmodal-c"></div></div></div>';
    modal=d.firstElementChild;
    document.body.appendChild(modal);
    modal.addEventListener('click',function(e){ if(e.target===modal) close(); });
    modal.querySelector('.fmodal-x').addEventListener('click',close);
    document.addEventListener('keydown',function(e){ if(e.key==='Escape'&&!modal.hidden) close(); });
    return modal;
  }
  function open(html){ var m=ensure(); m.querySelector('.fmodal-c').innerHTML=html; m.hidden=false; m.querySelector('.fmodal-panel').scrollTop=0; requestAnimationFrame(function(){ m.classList.add('show'); }); }
  function close(){ modal.classList.remove('show'); setTimeout(function(){ modal.hidden=true; },300); }
  function esc(s){ return String(s==null?'':s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/"/g,'&quot;'); }
  function row(k,v){ return v?'<div class="fm-row"><b>'+k+'</b><span>'+esc(v)+'</span></div>':''; }
  function pyr(f){
    if(!f||!((f.sal&&f.sal.length)||(f.cor&&f.cor.length)||(f.fon&&f.fon.length))) return '';
    function col(t,a){ return '<div class="fm-col"><h4>'+t+'</h4><p>'+(a&&a.length?a.map(esc).join(', '):'&mdash;')+'</p></div>'; }
    return '<div class="fm-pyr">'+col('Salida',f.sal)+col('Corazón',f.cor)+col('Fondo',f.fon)+'</div>';
  }
  function panel(img,alt,right){
    var photo=img?'<figure class="fm-photo" data-zoom role="button" tabindex="0" aria-label="Ampliar foto de '+esc(alt)+'"><img src="'+esc(img)+'" alt="'+esc(alt)+'" loading="lazy" decoding="async"></figure>':'';
    return '<div class="fm-wrap'+(img?'':' noimg')+'">'+photo+'<div class="fm-info">'+right+'</div></div>';
  }
  function abrirPerfume(h){
    var lista=(typeof PRODUCTS!=='undefined')?PRODUCTS:[];
    var p=null;
    for(var i=0;i<lista.length;i++){ if((lista[i].u||'').split('/').pop()===h){ p=lista[i]; break; } }
    if(!p) return;
    var f=window.FICHAS[h];
    var pres=(p.v&&p.v.length)?p.v.map(function(v){ return v.t+' · $'+v.p.toLocaleString('es-CO'); }).join(' · '):(p.p?'$'+p.p.toLocaleString('es-CO'):'');
    var right='<span class="eyebrow bare">'+esc([p.m,p.t].filter(Boolean).join(' · ')||'Perfume')+'</span>'
      +'<h3>'+esc(p.n)+'</h3>'
      +(f&&f.t?'<p class="fm-tag">&ldquo;'+esc(f.t)+'&rdquo;</p>':'')
      +(f&&f.r?'<p class="fm-res">'+esc(f.r)+'</p>':'')
      +'<div class="fm-rows">'
      +row('Género',(p.g&&p.g!=='·')?p.g:'')
      +row('Ocasión',p.o)
      +row('Familia olfativa',f&&f.fam)
      +row('Presentaciones',pres)
      +'</div>'
      +pyr(f)
      +((f&&(f.sal&&f.sal.length))?'':'<p class="fm-note">El proveedor no publica la pirámide olfativa de esta referencia.</p>');
    open(panel(p.i,p.n,right));
  }
  function abrirNatural(k){
    var f=window.FICHAS_NATURAL[k]; if(!f) return;
    var right='<span class="eyebrow bare">'+esc(f.cat)+'</span>'
      +'<h3>'+esc(f.nombre)+'</h3>'
      +(f.frase?'<p class="fm-tag">&ldquo;'+esc(f.frase)+'&rdquo;</p>':'')
      +(f.hace?'<p class="fm-res">'+esc(f.hace)+'</p>':'')
      +'<div class="fm-rows">'
      +row('Especie / Base',f.especie)
      +row('Activos',f.activos)
      +row('Beneficios físicos',f.fisico)
      +row('Presentación',f.present)
      +row('Precio',f.precio)
      +'</div>'
      +(f.nota?'<p class="fm-note">'+esc(f.nota)+'</p>':'');
    open(panel(f.img,f.nombre,right));
  }
  function despachar(el){
    if(el.hasAttribute('data-fh')){ abrirPerfume(el.getAttribute('data-fh')); return true; }
    if(el.hasAttribute('data-fh-nat')){ abrirNatural(el.getAttribute('data-fh-nat')); return true; }
    return false;
  }
  document.addEventListener('click',function(e){
    var b=e.target.closest('.ficha-btn');
    if(b){
      e.preventDefault();
      if(b.getAttribute('data-h')) abrirPerfume(b.getAttribute('data-h'));
      else if(b.getAttribute('data-ficha')) abrirNatural(b.getAttribute('data-ficha'));
      return;
    }
    var z=e.target.closest('[data-fh],[data-fh-nat]');
    if(z){ e.preventDefault(); despachar(z); }
  });
  document.addEventListener('keydown',function(e){
    if(e.key!=='Enter'&&e.key!==' ') return;
    var t=e.target;
    if(t&&t.matches&&t.matches('[data-fh],[data-fh-nat]')){ if(despachar(t)) e.preventDefault(); }
  });
})();
